// git_syntax.cpp
//
// Git .gitignore pattern matching support
//
// This module contains .gitignore pattern parsing and matching (fnmatch with ** support)
//
// Public API:
// - git_ignore_init(), git_ignore_free(), git_ignore_load(), git_ignore_matches()

#include "app.h"
#include "ui_theme.h"

// ============================================================================
// Gitignore Support
// ============================================================================

// Initialize gitignore list
void git_ignore_init(GitIgnoreList* list) {
    list->patterns = nullptr;
    list->count = 0;
    list->capacity = 0;
}

// Free gitignore list
void git_ignore_free(GitIgnoreList* list) {
    if (list->patterns) {
        delete[] list->patterns;
        list->patterns = nullptr;
    }
    list->count = 0;
    list->capacity = 0;
}

// Add a pattern to the list
static void git_ignore_add_pattern(GitIgnoreList* list, const char* pattern,
                                    bool is_negation, bool is_directory,
                                    bool is_anchored, const char* base_path) {
    // Grow capacity if needed
    if (list->count >= list->capacity) {
        size_t new_capacity = list->capacity == 0 ? 64 : list->capacity * 2;
        GitIgnorePattern* new_patterns = new GitIgnorePattern[new_capacity];
        if (list->patterns) {
            memcpy(new_patterns, list->patterns, list->count * sizeof(GitIgnorePattern));
            delete[] list->patterns;
        }
        list->patterns = new_patterns;
        list->capacity = new_capacity;
    }

    GitIgnorePattern* p = &list->patterns[list->count++];
    strncpy_s(p->pattern, pattern, sizeof(p->pattern) - 1);
    p->pattern[sizeof(p->pattern) - 1] = '\0';
    p->is_negation = is_negation;
    p->is_directory = is_directory;
    p->is_anchored = is_anchored;
    strncpy_s(p->base_path, base_path, sizeof(p->base_path) - 1);
    p->base_path[sizeof(p->base_path) - 1] = '\0';
}

// Load patterns from a .gitignore file
bool git_ignore_load(GitIgnoreList* list, const wchar_t* gitignore_path, const char* base_path) {
    char content[32768];
    size_t bytes_read = read_file(gitignore_path, content, sizeof(content));
    if (bytes_read == 0) {
        return false;
    }

    // Parse line by line
    char* line_start = content;
    char* p = content;

    while (*p) {
        if (*p == '\n' || *p == '\r') {
            *p = '\0';

            // Process line
            char* line = line_start;

            // Skip leading whitespace
            while (*line == ' ' || *line == '\t') line++;

            // Skip empty lines and comments
            if (*line && *line != '#') {
                bool is_negation = false;
                bool is_directory = false;
                bool is_anchored = false;

                // Check for negation
                if (*line == '!') {
                    is_negation = true;
                    line++;
                }

                // Check for anchoring (leading slash or contains slash)
                if (*line == '/') {
                    is_anchored = true;
                    line++;  // Skip leading slash
                } else {
                    // Check if pattern contains a slash (not at end)
                    for (const char* c = line; *c; c++) {
                        if (*c == '/' && *(c + 1) != '\0') {
                            is_anchored = true;
                            break;
                        }
                    }
                }

                // Check for trailing slash (directory only)
                size_t len = strlen(line);
                if (len > 0 && line[len - 1] == '/') {
                    is_directory = true;
                    line[len - 1] = '\0';  // Remove trailing slash
                    len--;
                }

                // Strip trailing whitespace
                while (len > 0 && (line[len - 1] == ' ' || line[len - 1] == '\t')) {
                    line[--len] = '\0';
                }

                if (len > 0) {
                    git_ignore_add_pattern(list, line, is_negation, is_directory,
                                          is_anchored, base_path);
                }
            }

            // Handle \r\n
            if (*p == '\0' && *(p + 1) == '\n') p++;

            line_start = p + 1;
        }
        p++;
    }

    // Process last line if no trailing newline
    if (line_start < p && *line_start && *line_start != '#') {
        char* line = line_start;
        while (*line == ' ' || *line == '\t') line++;

        if (*line) {
            bool is_negation = (*line == '!');
            if (is_negation) line++;

            bool is_anchored = (*line == '/');
            if (is_anchored) line++;
            else {
                for (const char* c = line; *c; c++) {
                    if (*c == '/' && *(c + 1) != '\0') {
                        is_anchored = true;
                        break;
                    }
                }
            }

            size_t len = strlen(line);
            bool is_directory = (len > 0 && line[len - 1] == '/');
            if (is_directory) line[--len] = '\0';

            while (len > 0 && (line[len - 1] == ' ' || line[len - 1] == '\t')) {
                line[--len] = '\0';
            }

            if (len > 0) {
                git_ignore_add_pattern(list, line, is_negation, is_directory,
                                      is_anchored, base_path);
            }
        }
    }

    return true;
}

// Match a single character class [abc], [a-z], [!abc]
// Returns: number of pattern chars consumed, 0 if no match
static int match_char_class(const char* pattern, char c) {
    if (*pattern != '[') return 0;

    const char* p = pattern + 1;
    bool negated = false;
    bool matched = false;

    if (*p == '!' || *p == '^') {
        negated = true;
        p++;
    }

    // Handle ] as first character (literal)
    if (*p == ']') {
        if (c == ']') matched = true;
        p++;
    }

    while (*p && *p != ']') {
        // Safe range check: peek p+1 and p+2 only if previous chars are non-null.
        // This prevents OOB read past the null terminator on truncated patterns
        // like "[a-".
        if (*(p + 1) == '-' && *(p + 2) != '\0' && *(p + 2) != ']') {
            // Range: a-z
            if (c >= *p && c <= *(p + 2)) matched = true;
            p += 3;
        } else {
            if (c == *p) matched = true;
            p++;
        }
    }

    if (*p != ']') return 0;  // Unclosed bracket

    int consumed = static_cast<int>(p - pattern + 1);
    return (matched != negated) ? consumed : 0;
}

// Git-style fnmatch with ** support
// pattern: the pattern to match
// path: the path to test
// depth: recursion depth (caps pathological patterns like '**********foo')
// Returns: true if matches
static bool fnmatch_git_impl(const char* pattern, const char* path, int depth);
static bool fnmatch_git(const char* pattern, const char* path) {
    return fnmatch_git_impl(pattern, path, 0);
}
static bool fnmatch_git_impl(const char* pattern, const char* path, int depth) {
    // Cap recursion to prevent stack overflow on adversarial .gitignore patterns.
    constexpr int MAX_FNMATCH_DEPTH = 64;
    if (depth > MAX_FNMATCH_DEPTH) return false;

    const char* p = pattern;
    const char* s = path;

    while (*p && *s) {
        if (*p == '*') {
            // Collapse runs of '*' (and treat '**' specially) so '*****' doesn't
            // explode recursive backtracking.
            bool is_double = (*(p + 1) == '*');
            while (*p == '*') p++;
            if (is_double) {
                // ** matches any path segments
                if (*p == '/') p++;  // Skip trailing slash after **

                if (*p == '\0') return true;  // ** at end matches everything

                // Try matching remainder at each position
                while (*s) {
                    if (fnmatch_git_impl(p, s, depth + 1)) return true;
                    s++;
                }
                return fnmatch_git_impl(p, s, depth + 1);  // Try at end too
            } else {
                // * matches anything except /
                if (*p == '\0') {
                    // * at end: match if no more slashes
                    while (*s) {
                        if (*s == '/') return false;
                        s++;
                    }
                    return true;
                }

                // Try matching at each position (no slash crossing)
                while (*s && *s != '/') {
                    if (fnmatch_git_impl(p, s, depth + 1)) return true;
                    s++;
                }
                return fnmatch_git_impl(p, s, depth + 1);
            }
        } else if (*p == '?') {
            // ? matches any single character except /
            if (*s == '/' || *s == '\0') return false;
            p++;
            s++;
        } else if (*p == '[') {
            // Character class
            int consumed = match_char_class(p, *s);
            if (consumed == 0) return false;
            p += consumed;
            s++;
        } else if (*p == '\\' && *(p + 1)) {
            // Escaped character
            p++;
            if (*p != *s) return false;
            p++;
            s++;
        } else {
            // Literal match
            if (*p != *s) return false;
            p++;
            s++;
        }
    }

    // Handle trailing * or **
    while (*p == '*') p++;

    return (*p == '\0' && *s == '\0');
}

// Check if a path matches any gitignore pattern
// Returns: true if path should be ignored
bool git_ignore_matches(GitIgnoreList* list, const char* path, bool is_dir) {
    if (!list || !path || list->count == 0) return false;

    bool ignored = false;

    // Process patterns in order (later patterns can override)
    for (size_t i = 0; i < list->count; i++) {
        GitIgnorePattern* p = &list->patterns[i];

        // Directory-only pattern doesn't match files
        if (p->is_directory && !is_dir) continue;

        bool matches = false;

        if (p->is_anchored) {
            // Anchored pattern: must match from base_path
            // Check if path starts with base_path
            size_t base_len = strlen(p->base_path);
            if (base_len > 0) {
                if (strncmp(path, p->base_path, base_len) != 0) continue;
                if (path[base_len] != '/' && path[base_len] != '\0') continue;
                // Match relative part
                const char* rel_path = path + base_len;
                if (*rel_path == '/') rel_path++;
                matches = fnmatch_git(p->pattern, rel_path);
            } else {
                matches = fnmatch_git(p->pattern, path);
            }
        } else {
            // Non-anchored: can match anywhere in path
            // Try matching against the full path and each suffix
            const char* test = path;
            while (test && !matches) {
                matches = fnmatch_git(p->pattern, test);
                if (!matches) {
                    test = strchr(test, '/');
                    if (test) test++;  // Skip the slash
                }
            }
        }

        if (matches) {
            ignored = !p->is_negation;
        }
    }

    return ignored;
}
